// Compile the Morning Image Brief (DISPATCH_GATE Layer 5 format)
// Inputs arrive from the three upstream branches; adapt field access to your sources.

const status = $('Read Overnight Status').first()?.json?.data || 'No overnight status found.';
const emails = $('Gmail — Unread').all().map(e => e.json) || [];
const social = $('Social Analytics').first()?.json || {};

const inboxLines = emails.length
  ? emails.map((e, i) => `   ${i + 1}. ${e.From || e.from || 'unknown'} — ${e.Subject || e.subject || '(no subject)'}  [approve/edit/skip]`).join('\n')
  : '   (inbox clear)';

const brief = [
  `☀️ MORNING BRIEF — ${new Date().toISOString().slice(0,10)}`,
  ``,
  `BUILD (overnight): see STATUS — ${String(status).split('\n').find(l => l.includes('Last Agent Run')) || 'review STATUS.md'}`,
  `SOCIAL: ${JSON.stringify(social).slice(0, 200)}`,
  `INBOX (${emails.length} need you):`,
  inboxLines,
  ``,
  `ONE THING: <orchestrator fills the single most important action>`
].join('\n');

return [{ json: { brief } }];
